CONSTITUTION = [
    "ACCURACY: Every factual claim must be verifiable. Flag any statement that could be wrong.",
    "COMPLETENESS: The output must address every part of the task. Flag missing parts.",
    "SAFETY: The output must not suggest harmful, illegal, or unethical actions. Flag any.",
    "CONCISENESS: Remove padding or repetition that does not add value. Flag verbose sections.",
]

CONSTITUTIONAL_CRITIQUE_PROMPT = """
Evaluate the output against this principle:
Principle: {principle}

Task: {task}
Output: {output}

Does the output violate this principle? If yes, quote the offending text and explain.
If no violation, respond: PASS
"""

def constitutional_critique(
    client: anthropic.Anthropic,
    task: str,
    output: str,
) -> list[str]:
    violations = []
    for principle in CONSTITUTION:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=256,
            messages=[{"role":"user","content":
                CONSTITUTIONAL_CRITIQUE_PROMPT.format(
                    principle=principle, task=task, output=output
                )}],
        )
        result = resp.content[0].text.strip()
        if result != "PASS":
            violations.append(f"{principle.split(':')[0]}: {result}")
    return violations

SCORED_CRITIQUE_PROMPT = """Score and critique the output on four dimensions.

Task: {task}
Output:
{output}

Respond with JSON:
{{
  "accuracy":     {{"score": 0-10, "issues": [str]}},
  "completeness": {{"score": 0-10, "issues": [str]}},
  "clarity":      {{"score": 0-10, "issues": [str]}},
  "conciseness":  {{"score": 0-10, "issues": [str]}},
  "overall":      0-10
}}
"""

def scored_critique(
    client,
    task: str,
    output: str,
) -> dict:
    import json, re
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{"role":"user","content":
            SCORED_CRITIQUE_PROMPT.format(task=task, output=output)}],
    )
    raw = resp.content[0].text
    m = re.search(r"\{.*\}", raw, re.DOTALL)
    return json.loads(m.group()) if m else {"overall": 10}


def critique_revise_scored(
    client,
    task: str,
    initial_output: str,
    threshold: int = 8,
    max_rounds: int = 3,
) -> str:
    output = initial_output
    for _ in range(max_rounds):
        scores = scored_critique(client, task, output)
        if scores.get("overall", 10) >= threshold:
            break
        # Collect all issues into one critique text for the reviser
        issues = []
        for dim in ["accuracy", "completeness", "clarity", "conciseness"]:
            for issue in scores.get(dim, {}).get("issues", []):
                issues.append(f"[{dim.upper()}] {issue}")
        if not issues:
            break
        output = revise(client, task, output, "\n".join(issues))
    return output
